// src/components/Navbar.jsx
import { useState, useEffect } from "react";

const styles = {
  nav: {
    position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
    display: "flex", alignItems: "center", justifyContent: "space-between",
    padding: "0 48px", height: 68,
    transition: "all 0.3s",
  },
  navScrolled: {
    background: "rgba(248,250,255,0.90)",
    backdropFilter: "blur(20px)",
    borderBottom: "1px solid var(--border)",
    boxShadow: "0 2px 20px rgba(29,78,216,0.06)",
  },
  navTransparent: {
    background: "transparent",
  },
  logo: {
    fontFamily: "var(--font-display)",
    fontWeight: 800, fontSize: "1.4rem",
    letterSpacing: "-0.5px",
    display: "flex", alignItems: "center", gap: 2,
    color: "var(--ink)", textDecoration: "none",
    cursor: "pointer",
  },
  logoBlue: { color: "var(--blue)" },
  dot: {
    width: 8, height: 8, background: "var(--yellow)",
    borderRadius: "50%", display: "inline-block",
    marginLeft: 3, animation: "pulse 2s ease-in-out infinite",
  },
  links: { display: "flex", alignItems: "center", gap: 6 },
  link: {
    padding: "8px 16px", borderRadius: 8,
    fontSize: "0.9rem", fontFamily: "var(--font-display)", fontWeight: 600,
    border: "none", background: "transparent", color: "var(--mid)",
    cursor: "pointer", transition: "all 0.2s",
  },
  writeBtn: {
    padding: "9px 20px", borderRadius: 8,
    fontSize: "0.88rem", fontFamily: "var(--font-display)", fontWeight: 700,
    border: "none", background: "var(--blue)", color: "#fff",
    cursor: "pointer", transition: "all 0.2s",
    display: "flex", alignItems: "center", gap: 6,
  },
  demoBadge: {
    fontSize: "0.72rem", background: "var(--yellow)",
    color: "var(--ink)", padding: "3px 10px", borderRadius: 100,
    fontFamily: "var(--font-display)", fontWeight: 700,
  },
};

export default function Navbar({ onWriteClick, isDemo }) {
  const [scrolled, setScrolled] = useState(false);
  const [activeSection, setActiveSection] = useState("home");

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
    setActiveSection(id);
  };

  return (
    <nav style={{ ...styles.nav, ...(scrolled ? styles.navScrolled : styles.navTransparent) }}>
      <div style={styles.logo} onClick={() => scrollTo("home")}>
        AERO<span style={styles.logoBlue}>BLOG</span>
        <span style={styles.dot} />
        {isDemo && <span style={styles.demoBadge}>DEMO</span>}
      </div>

      <div style={styles.links}>
        {[
          { id: "features", label: "Features" },
          { id: "posts", label: "Posts" },
          { id: "about", label: "About" },
        ].map(({ id, label }) => (
          <button
            key={id}
            style={{
              ...styles.link,
              color: activeSection === id ? "var(--blue)" : "var(--mid)",
              background: activeSection === id ? "var(--bg-2)" : "transparent",
            }}
            onMouseEnter={(e) => {
              e.target.style.color = "var(--blue)";
              e.target.style.background = "var(--bg-2)";
            }}
            onMouseLeave={(e) => {
              e.target.style.color = activeSection === id ? "var(--blue)" : "var(--mid)";
              e.target.style.background = activeSection === id ? "var(--bg-2)" : "transparent";
            }}
            onClick={() => scrollTo(id)}
          >
            {label}
          </button>
        ))}

        <button
          style={styles.writeBtn}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "#1e40af";
            e.currentTarget.style.transform = "translateY(-1px)";
            e.currentTarget.style.boxShadow = "0 6px 20px rgba(29,78,216,0.35)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "var(--blue)";
            e.currentTarget.style.transform = "translateY(0)";
            e.currentTarget.style.boxShadow = "none";
          }}
          onClick={onWriteClick}
        >
          ✏️ Write Post
        </button>
      </div>
    </nav>
  );
}
